import React, { useState, useEffect, useRef } from 'react';
import io from 'socket.io-client';
import './App.css';

function App() {
  const [socket, setSocket] = useState(null);
  const [status, setStatus] = useState('initial');
  const [messages, setMessages] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [partnerId, setPartnerId] = useState(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);

  const messagesEndRef = useRef(null);
  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const recordingIntervalRef = useRef(null);

  useEffect(() => {
    const newSocket = io('http://localhost:5000', {
      reconnection: true,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
      reconnectionAttempts: 5
    });

    newSocket.on('connect', () => {
      console.log('Connected to server');
    });

    newSocket.on('waiting', () => {
      setStatus('waiting');
      setMessages([]);
    });

    newSocket.on('chat-started', (data) => {
      setStatus('chatting');
      setPartnerId(data.partnerId);
      setMessages([{ type: 'system', text: '✅ Connected to a random user!' }]);
    });

    newSocket.on('receive-message', (data) => {
      if (data.isVoice) {
        setMessages(prev => [...prev, {
          type: 'received',
          isVoice: true,
          audioData: data.audioData,
          time: data.timestamp
        }]);
      } else {
        setMessages(prev => [...prev, {
          type: 'received',
          text: data.message,
          time: data.timestamp
        }]);
      }
    });

    newSocket.on('chat-ended', () => {
      setStatus('ended');
      setPartnerId(null);
    });

    setSocket(newSocket);

    return () => newSocket.close();
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const startChat = () => {
    if (socket) {
      socket.emit('start-chat');
    }
  };

  const sendMessage = () => {
    if (inputValue.trim() && socket && status === 'chatting') {
      setMessages(prev => [...prev, { type: 'sent', text: inputValue }]);
      socket.emit('send-message', { message: inputValue, isVoice: false });
      setInputValue('');
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      let seconds = 0;

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();

        reader.onloadend = () => {
          const audioData = reader.result;
          setMessages(prev => [...prev, { 
            type: 'sent', 
            isVoice: true, 
            audioData: audioData,
            duration: recordingTime
          }]);
          socket.emit('send-message', { audioData: audioData, isVoice: true, duration: recordingTime });
        };

        reader.readAsArrayBuffer(audioBlob);
        stream.getTracks().forEach(track => track.stop());
        setRecordingTime(0);
      };

      mediaRecorder.start();
      setIsRecording(true);

      recordingIntervalRef.current = setInterval(() => {
        seconds++;
        setRecordingTime(seconds);
      }, 1000);
    } catch (error) {
      console.error('Error accessing microphone:', error);
      alert('Unable to access microphone. Please check permissions.');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      clearInterval(recordingIntervalRef.current);
    }
  };

  return (
    <div className="app">
      <header className="header">
        <h1>🎲 Random Chat</h1>
        <p>Connect with random strangers and have fun conversations!</p>
      </header>

      <div className="container">
        {status === 'initial' && (
          <div className="welcome">
            <div className="welcome-card">
              <h2>Welcome to Random Chat!</h2>
              <p>Meet and chat with random people from around the world.</p>
              <button onClick={startChat} className="btn btn-primary">
                Start Chatting 🚀
              </button>
            </div>
          </div>
        )}

        {status === 'waiting' && (
          <div className="waiting">
            <div className="spinner"></div>
            <p>Looking for a chat partner...</p>
          </div>
        )}

        {status === 'chatting' && (
          <div className="chat">
            <div className="chat-header">
              <h2>💬 Chat with User #{partnerId.slice(-5)}</h2>
              <button onClick={endChat} className="btn btn-danger">
                End Chat ✌️
              </button>
            </div>

            <div className="messages">
              {messages.map((msg, idx) => (
                <div key={idx} className={`message message-${msg.type}`}>
                  {msg.isVoice ? (
                    <VoiceMessagePlayer audioData={msg.audioData} duration={msg.duration} />
                  ) : (
                    msg.text
                  )}
                </div>
              ))}
              <div ref={messagesEndRef} />
            </div>

            <div className="input-area">
              <input
                type="text"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
                placeholder="Type a message..."
                className="input"
                disabled={isRecording}
              />
              <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`btn btn-mic ${isRecording ? 'recording' : ''}`}
                title={isRecording ? 'Stop recording' : 'Start recording'}
              >
                {isRecording ? `⏹️ ${recordingTime}s` : '🎤'}
              </button>
              <button 
                onClick={sendMessage} 
                className="btn btn-send"
                disabled={!inputValue.trim() || isRecording}
              >
                Send 📤
              </button>
            </div>
          </div>
        )}

        {status === 'ended' && (
          <div className="ended">
            <div className="ended-card">
              <h2>Chat Ended 👋</h2>
              <p>Thanks for chatting! Would you like to meet another random user?</p>
              <button onClick={startNew} className="btn btn-primary">
                Chat Again 🔄
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// Voice Message Player Component
function VoiceMessagePlayer({ audioData, duration }) {
  const audioRef = useRef(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);

  useEffect(() => {
    if (audioRef.current && audioData) {
      const blob = new Blob([audioData], { type: 'audio/webm' });
      const url = URL.createObjectURL(blob);
      audioRef.current.src = url;
    }
  }, [audioData]);

  const handlePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        audioRef.current.play();
        setIsPlaying(true);
      }
    }
  };

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
    }
  };

  const handleEnded = () => {
    setIsPlaying(false);
    setCurrentTime(0);
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="voice-message">
      <audio 
        ref={audioRef} 
        onTimeUpdate={handleTimeUpdate}
        onEnded={handleEnded}
      />
      <button 
        className="btn-play"
        onClick={handlePlay}
        title={isPlaying ? 'Pause' : 'Play'}
      >
        {isPlaying ? '⏸️' : '▶️'}
      </button>
      <div className="audio-progress">
        <div className="progress-bar">
          <div 
            className="progress-fill" 
            style={{
              width: duration ? `${(currentTime / duration) * 100}%` : '0%'
            }}
          />
        </div>
      </div>
      <span className="audio-time">
        {formatTime(currentTime)} / {formatTime(duration || 0)}
      </span>
    </div>
  );
}
